`app.js` declares all logic as top-level `function` statements in a plain script (no `module.exports`, no ES `export`). If you `require('./app.js')` from a test, Node wraps the file in a function scope — `addTodo`, `toggleTodo`, `filteredTodos`, etc. never become reachable from outside. The script also runs its setup (`loadTodos(); render();`) immediately on load and queries `document.getElementById(...)` at the top, so importing it requires a matching DOM already in place.

Recommended minimal fix (no behavior change, browser-safe):
```js
// end of app.js
if (typeof module !== "undefined" && module.exports) {
  module.exports = {
    state, loadTodos, saveTodos, createId, addTodo, updateTodo, toggleTodo,
    deleteTodo, clearCompleted, toggleAll, setFilter, filteredTodos,
    getActiveCount, getCompletedCount,
  };
}
```
Until that lands, true unit tests aren't possible — only DOM-driven integration tests are. I've written skeletons for both tracks below; say the word if you want me to apply the export shim and a `package.json` with Jest.

---

**Track A — pure logic (needs the export shim from §0).** `npm i -D jest` and add `"test": "jest"` to a new `package.json`.

```js
// app.unit.test.js
const { state, addTodo, updateTodo, toggleTodo, deleteTodo, clearCompleted,
        toggleAll, filteredTodos, getActiveCount, getCompletedCount,
        loadTodos, saveTodos, createId } = require("./app");

beforeEach(() => {
  localStorage.clear();
  state.todos = [];
  state.filter = "all";
});

describe("createId", () => {
  test("generates unique ids across many calls", () => {
    const ids = new Set(Array.from({ length: 1000 }, () => createId()));
    expect(ids.size).toBe(1000);
  });
});

describe("addTodo", () => {
  test("adds a trimmed todo to the front of the list", () => { /* ... */ });
  test.each(["", "   ", "\n\t"])("ignores blank input %p", (text) => {
    addTodo(text);
    expect(state.todos).toHaveLength(0);
  });
});

describe("toggleTodo / deleteTodo / updateTodo with unknown id", () => {
  test("toggleTodo on missing id is a no-op and does not persist", () => { /* ... */ });
  test("deleteTodo on missing id leaves list unchanged", () => { /* ... */ });
});

describe("clearCompleted", () => {
  test("no-ops when nothing is completed", () => { /* ... */ });
  test("removes only completed todos", () => { /* ... */ });
});

describe("toggleAll", () => {
  test("no-ops on empty list", () => { /* ... */ });
  test("marks all complete when some are pending", () => { /* ... */ });
  test("un-marks all when every todo is already complete", () => { /* ... */ });
});

describe("filteredTodos", () => {
  test.each([["active"], ["done"], ["all"], ["bogus-filter"]])("filter=%s", (filter) => { /* ... */ });
});

describe("getActiveCount / getCompletedCount", () => {
  test("sum to total todo count", () => { /* ... */ });
});

describe("loadTodos error handling", () => {
  test("malformed JSON resets todos to [] and warns", () => { /* ... */ });
  test("valid JSON but non-array payload leaves state untouched", () => { /* ... */ });
  test("localStorage.getItem throwing does not crash init", () => {
    jest.spyOn(Storage.prototype, "getItem").mockImplementation(() => { throw new Error("blocked"); });
    expect(() => loadTodos()).not.toThrow(); // currently FAILS — bug to fix
  });
});

describe("saveTodos error handling", () => {
  test("setItem throwing (quota exceeded) does not crash sync()", () => {
    jest.spyOn(Storage.prototype, "setItem").mockImplementation(() => {
      throw new DOMException("quota", "QuotaExceededError");
    });
    expect(() => addTodo("task")).not.toThrow(); // currently FAILS — bug to fix
  });
});
```

**Track B — DOM integration (works today, no source changes).**

```js
// app.dom.test.js
const fs = require("fs");
const path = require("path");

function loadApp() {
  document.documentElement.innerHTML = fs.readFileSync(
    path.resolve(__dirname, "index.html"), "utf8"
  );
  localStorage.clear();
  jest.resetModules();
  require("./app.js");
}

beforeEach(loadApp);

test("submitting the form adds a visible todo item and updates the counter", () => {
  const input = document.getElementById("todoInput");
  input.value = "Buy milk";
  document.getElementById("todoForm").dispatchEvent(new Event("submit", { cancelable: true }));
  expect(document.querySelectorAll(".todo-item")).toHaveLength(1);
  expect(document.getElementById("activeText").textContent).toMatch(/1 tarefa pendente/);
});

test("clicking the check button toggles completed state and persists it", () => { /* ... */ });

test("clicking the trash button removes the item from DOM and storage", () => { /* ... */ });

test("filter buttons show only matching todos and toggle aria/active state", () => { /* ... */ });

test("clear-completed button is disabled with none completed, enabled otherwise", () => { /* ... */ });

test("mark-all button label flips between 'Marcar todas' and 'Desmarcar todas'", () => { /* ... */ });

describe("inline edit", () => {
  test("double-click opens an input pre-filled and focused with text selected", () => { /* ... */ });
  test("Enter saves the new text", () => { /* ... */ });
  test("Escape discards changes and restores original text", () => { /* ... */ });
  test("blur saves like Enter, and Enter-then-blur does not double-save", () => { /* ... */ });
  test("saving a blank edit keeps the original text instead of emptying it", () => { /* ... */ });
});

test("todos persist across a reload (localStorage round-trip)", () => {
  // add via UI, reload module without clearing localStorage, assert item still renders
});

test("a 'storage' event from another tab re-renders with new data", () => {
  localStorage.setItem("simple_todos_v1", JSON.stringify([{ id: "1", text: "x", completed: false }]));
  window.dispatchEvent(new StorageEvent("storage", { key: "simple_todos_v1" }));
  expect(document.querySelectorAll(".todo-item")).toHaveLength(1);
});

test("XSS regression: todo text is rendered as text, not executed as HTML", () => {
  const input = document.getElementById("todoInput");
  input.value = "<img src=x onerror=alert(1)>";
  document.getElementById("todoForm").dispatchEvent(new Event("submit", { cancelable: true }));
  expect(document.querySelector(".todo-text").innerHTML).not.toContain("<img");
});
```

---

Two concrete bugs surfaced during this analysis (not just missing tests): `loadTodos`'s `getItem` call is unprotected by the try/catch, and `saveTodos` has no error handling at all — both can crash or silently desync the UI. Want me to set up `package.json` + Jest, add the export shim, and write these tests for real (including fixing those two issues)?

